import { create } from "zustand";

interface Store {
    barcode: string[];
    addItem: (barcode: string) => void;
}

interface Quantity {
    quantity: number[];
    minus: (by?: number) => void;
}

export const usePOSStore = create<Store>()((set) => ({
    barcode: [],
    addItem: (barcodes) => set((state) => ({ barcode: [...state.barcode, barcodes] })),
}));
