"use client";

import React from 'react'
import { Button } from './ui/button'
import { useQuantityHandler } from '@/store/posStore'

interface Props {
    id: string;
    prodQuantity: number;
}

const AddToCart = (quantities: Props) => {
    const { quantity, minus } = useQuantityHandler();
    return (
        // <p className='md:text-xl text-red-900'>SOLD OUT</p> :
        <Button
            className="text-white bg-blue-700 hover:bg-blue-800 font-medium rounded-lg text-sm px-5 py-2.5 text-center cursor-pointer"
            onClick={() => minus()}
        >
            Add to Cart
        </Button>
    )
}
export default AddToCart